const doc = $('Create Google Interview Brief Doc').first().json;
const brief = $('Merge Final Deliverables').first().json;

function cleanText(value) {
  return String(value || "")
    .replace(/\\\\n/g, "\n")
    .replace(/\\n/g, "\n")
    .replace(/\\\\t/g, "\t")
    .replace(/\\t/g, "\t")
    .replace(/\r\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function processBold(text, baseIndex, styleRequests) {
  let output = "";
  let cursor = 0;
  const regex = /\*\*(.*?)\*\*/g;
  let match;

  while ((match = regex.exec(text)) !== null) {
    output += text.slice(cursor, match.index);

    const boldText = match[1];
    const boldStart = baseIndex + output.length;
    output += boldText;
    const boldEnd = baseIndex + output.length;

    styleRequests.push({
      updateTextStyle: {
        range: {
          startIndex: boldStart,
          endIndex: boldEnd
        },
        textStyle: {
          bold: true
        },
        fields: "bold"
      }
    });

    cursor = match.index + match[0].length;
  }

  output += text.slice(cursor);
  return output;
}

const rawMarkdown = cleanText(brief.final_markdown);
const lines = rawMarkdown.split("\n");

let finalText = "";
const formattingRequests = [];

for (const line of lines) {
  const lineStart = 1 + finalText.length;
  let outputLine = line;
  let paragraphStyle = null;
  let makeBullet = false;

  if (line.startsWith("# ")) {
    outputLine = line.replace(/^# /, "");
    paragraphStyle = "HEADING_1";
  } else if (line.startsWith("## ")) {
    outputLine = line.replace(/^## /, "");
    paragraphStyle = "HEADING_2";
  } else if (line.startsWith("### ")) {
    outputLine = line.replace(/^### /, "");
    paragraphStyle = "HEADING_3";
  } else if (line.trim() === "---") {
    outputLine = "────────────────────────────";
  } else if (line.startsWith("- ")) {
    outputLine = line.replace(/^- /, "");
    makeBullet = true;
  }

  outputLine = processBold(outputLine, lineStart, formattingRequests);

  finalText += outputLine + "\n";

  const lineEnd = 1 + finalText.length;

  if (paragraphStyle) {
    formattingRequests.push({
      updateParagraphStyle: {
        range: {
          startIndex: lineStart,
          endIndex: lineEnd
        },
        paragraphStyle: {
          namedStyleType: paragraphStyle
        },
        fields: "namedStyleType"
      }
    });
  }

  if (makeBullet && outputLine.trim()) {
    formattingRequests.push({
      createParagraphBullets: {
        range: {
          startIndex: lineStart,
          endIndex: lineEnd
        },
        bulletPreset: "BULLET_DISC_CIRCLE_SQUARE"
      }
    });
  }
}

return [
  {
    json: {
      document_id: doc.id,
      request_body: {
        requests: [
          {
            insertText: {
              location: {
                index: 1
              },
              text: finalText.trim()
            }
          },
          ...formattingRequests
        ]
      }
    }
  }
];

const doc = $('Create Research Packet Doc').first().json;
const manifest = $('Generate Source Manifest').first().json;

function cleanText(value) {
  return String(value || "")
    .replace(/\\\\n/g, "\n")
    .replace(/\\n/g, "\n")
    .replace(/\\\\t/g, "\t")
    .replace(/\\t/g, "\t")
    .replace(/\r\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

const researchPacketMarkdown = `# ${manifest.company} Full Research Packet

## Interview Context

- Company: ${manifest.company}
- Target Role Level: ${manifest.role_level}
- Industry / Space: ${manifest.industry}
- Research Depth: ${manifest.research_depth}
- Sources Selected: ${manifest.source_count}

---

## Deep Source Research Packet

${manifest.deep_research_packet || "No deep research packet available."}

---

## Source Manifest

${manifest.manifest_markdown || ""}
`;

const cleanPacket = cleanText(researchPacketMarkdown);

return [
  {
    json: {
      document_id: doc.id,
      request_body: {
        requests: [
          {
            insertText: {
              location: {
                index: 1
              },
              text: cleanPacket
            }
          }
        ]
      }
    }
  }
];
